document.addEventListener("DOMContentLoaded",()=>{let e=document.querySelectorAll(".news-btn"),t=document.querySelectorAll(".news-card");0!==e.length&&0!==t.length&&e.forEach(l=>{l.addEventListener("click",()=>{e.forEach(e=>{e.classList.remove("active")}),l.classList.add("active");let s=l.getAttribute("data-filter");t.forEach(e=>{"all"===s?(e.style.display="block",setTimeout(()=>{e.style.opacity="1",e.style.transform="scale(1)"},100)):e.classList.contains(s)?(e.style.display="block",setTimeout(()=>{e.style.opacity="1",e.style.transform="scale(1)"},100)):(e.style.opacity="0",e.style.transform="scale(0.8)",setTimeout(()=>{e.style.display="none"},300))})})})});